+static bool doubleFromString(std::string str, double& val)
+{
+  std::string str_stripped = boost::trim_copy(str);
+  const char *s = str_stripped.c_str();
+  char *e = 0;
+  val = std::strtod(s, &e);
+  return e && e!=s && *e == 0;
+}
